// Validar dados de entrada
const input = $input.first().json;
let updateData;

try {
  updateData = input.body;
  if (!updateData || typeof updateData !== 'object') {
    throw new Error('Dados inválidos: esperado objeto com dados de atualização');
  }
} catch (error) {
  console.log(JSON.stringify({
    timestamp: new Date().toISOString(),
    route: 'update_services',
    event: 'validation_error',
    message: error.message,
    level: 'error'
  }));
  return {
    statusCode: 400,
    body: { ok: false, error: 'Dados inválidos', details: error.message }
  };
}

// Normalizar dados de atualização
const normalized = {
  ACTION: updateData.ACTION || updateData.action || 'UNKNOWN',
  RUN_STATUS: parseInt(updateData.RUN_STATUS || updateData.run_status || 0),
  PROGRESS_VALUE: parseInt(updateData.PROGRESS_VALUE || updateData.progress_value || 0),
  RUN_AFTER: parseInt(updateData.RUN_AFTER || updateData.run_after || 720)
};

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'update_services',
  event: 'data_validated',
  action: normalized.ACTION,
  status: normalized.RUN_STATUS,
  level: 'info'
}));

return { normalized };

// Sucesso
const result = $input.first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'update_services',
  event: 'update_success',
  affected_rows: result.affectedRows || 0,
  level: 'info'
}));

return {
  statusCode: 201,
  body: { ok: true, message: 'Service status updated successfully' }
};

// Erro de banco
const errData = $input.first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'update_services',
  event: 'db_error',
  message: errData.message || 'Unknown DB error',
  level: 'error'
}));

return {
  statusCode: 500,
  body: { ok: false, error: 'Database error', message: 'Could not update service status' }
};
